import React from 'react';
import { BrowserRouter, Routes, Route, NavLink } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import Dashboard from './pages/Dashboard';
import CameraPage from './pages/CameraPage';
import EmployeePage from './pages/EmployeePage';
import ReportsPage from './pages/ReportsPage';
import './App.css';

function Sidebar() {
  const links = [
    { to: '/', icon: '📊', label: 'Dashboard' },
    { to: '/cameras', icon: '📹', label: 'Live Cameras' },
    { to: '/employees', icon: '👥', label: 'Employees' },
    { to: '/reports', icon: '📋', label: 'Reports' },
  ];
  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <span className="logo-icon">🏭</span>
        <div>
          <div className="logo-title">FactoryFace</div>
          <div className="logo-sub">Attendance System</div>
        </div>
      </div>
      <nav className="sidebar-nav">
        {links.map(l => (
          <NavLink key={l.to} to={l.to} end={l.to === '/'} className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`}>
            <span>{l.icon}</span>
            <span>{l.label}</span>
          </NavLink>
        ))}
      </nav>
      <div className="sidebar-footer">v1.0.0 &copy; 2025</div>
    </aside>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <div className="app-layout">
        <Sidebar />
        <main className="app-main">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/cameras" element={<CameraPage />} />
            <Route path="/employees" element={<EmployeePage />} />
            <Route path="/reports" element={<ReportsPage />} />
          </Routes>
        </main>
      </div>
      <Toaster position="top-right" toastOptions={{ style: { background: '#1e293b', color: '#e2e8f0', border: '1px solid #334155' } }} />
    </BrowserRouter>
  );
}
